import type { ReactNode } from "react";

import type { WebUIVariant } from "../../types/theme";

import classes from "./typo.module.css";

interface Props {
  children: ReactNode;
  color?: WebUIVariant;
}

interface HeadingProps extends Props {
  id?: string;
}

function H1({ children, color = "main", id }: HeadingProps) {
  return (
    <h1 data-imf-ui-component="Typo.H1" data-color={color} className={classes.TypoH1} id={id}>
      {children}
    </h1>
  );
}
H1.displayName = "Typo.H1";

function H2({ children, color = "main", id }: HeadingProps) {
  return (
    <h2 data-imf-ui-component="Typo.H2" data-color={color} className={classes.TypoH2} id={id}>
      {children}
    </h2>
  );
}
H2.displayName = "Typo.H2";

function H3({ children, color = "main", id }: HeadingProps) {
  return (
    <h3 data-imf-ui-component="Typo.H3" data-color={color} className={classes.TypoH3} id={id}>
      {children}
    </h3>
  );
}
H3.displayName = "Typo.H3";

function H4({ children, color = "main", id }: HeadingProps) {
  return (
    <h4 data-imf-ui-component="Typo.H4" data-color={color} className={classes.TypoH4} id={id}>
      {children}
    </h4>
  );
}
H4.displayName = "Typo.H4";

function P({ children, color = "main" }: Props) {
  return (
    <p data-imf-ui-component="Typo.P" data-color={color} className={classes.TypoP}>
      {children}
    </p>
  );
}
P.displayName = "Typo.P";

function Lead({ children, color = "support" }: Props) {
  return (
    <p data-imf-ui-component="Typo.Lead" data-color={color} className={classes.TypoLead}>
      {children}
    </p>
  );
}
Lead.displayName = "Typo.Lead";

function Small({ children, color = "minor" }: Props) {
  return (
    <small data-imf-ui-component="Typo.Small" data-color={color} className={classes.TypoSmall}>
      {children}
    </small>
  );
}
Small.displayName = "Typo.Small";

function Blockquote({ children, color = "minor" }: Props) {
  return (
    <blockquote data-imf-ui-component="Typo.Blockquote" data-color={color} className={classes.TypoBlockquote}>
      {children}
    </blockquote>
  );
}
Blockquote.displayName = "Typo.Blockquote";

function InlineCode({ children, color = "main" }: Props) {
  return (
    <code data-imf-ui-component="Typo.InlineCode" data-color={color} className={classes.TypoInlineCode}>
      {children}
    </code>
  );
}
InlineCode.displayName = "Typo.InlineCode";

function Highlight({ children, color = "main" }: Props) {
  return (
    <mark data-imf-ui-component="Typo.Highlight" data-color={color} className={classes.TypoHighlight}>
      {children}
    </mark>
  );
}
Highlight.displayName = "Typo.Highlight";

function OrderedList({ children, color = "main" }: Props) {
  return (
    <ol data-imf-ui-component="Typo.OrderedList" data-color={color} className={classes.TypoOrderedList}>
      {children}
    </ol>
  );
}
OrderedList.displayName = "Typo.OrderedList";

function UnorderedList({ children, color = "main" }: Props) {
  return (
    <ul data-imf-ui-component="Typo.UnorderedList" data-color={color} className={classes.TypoUnorderedList}>
      {children}
    </ul>
  );
}
UnorderedList.displayName = "Typo.UnorderedList";

/**
 * Typography primitives. Exposed as a namespace (`Typo.H1`, `Typo.P`, ...) rather
 * than flat exports — typography is a tight conceptual cluster and dot-notation
 * reads better at call sites that mix many of these together. Local deviation
 * from the repo's default flat-export convention; Slider and other primitives
 * remain flat.
 */
export const Typo = {
  H1,
  H2,
  H3,
  H4,
  P,
  Lead,
  Small,
  Blockquote,
  InlineCode,
  Highlight,
  OrderedList,
  UnorderedList
} as const;

@layer imf-ui.components {
  .TypoH1,
  .TypoH2,
  .TypoH3,
  .TypoH4,
  .TypoP,
  .TypoLead,
  .TypoSmall,
  .TypoBlockquote,
  .TypoInlineCode,
  .TypoHighlight,
  .TypoOrderedList,
  .TypoUnorderedList {
    margin: 0;
    letter-spacing: var(--imf-ui-font-letterspacing-normal);
  }

  .TypoH1 {
    font-family: var(--imf-ui-font-family-heading);
    font-size: var(--imf-ui-font-size-fluid-3);
    font-weight: var(--imf-ui-font-weight-8);
    line-height: var(--imf-ui-font-lineheight-00);
    letter-spacing: var(--imf-ui-font-letterspacing-tight);
  }

  .TypoH2 {
    font-family: var(--imf-ui-font-family-heading);
    font-size: var(--imf-ui-font-size-fluid-2);
    font-weight: var(--imf-ui-font-weight-7);
    line-height: var(--imf-ui-font-lineheight-0);
    letter-spacing: var(--imf-ui-font-letterspacing-tight);
  }

  .TypoH3 {
    font-family: var(--imf-ui-font-family-heading);
    font-size: var(--imf-ui-font-size-5);
    font-weight: var(--imf-ui-font-weight-6);
    line-height: var(--imf-ui-font-lineheight-1);
  }

  .TypoH4 {
    font-family: var(--imf-ui-font-family-heading);
    font-size: var(--imf-ui-font-size-4);
    font-weight: var(--imf-ui-font-weight-6);
    line-height: var(--imf-ui-font-lineheight-1);
  }

  .TypoP {
    font-family: var(--imf-ui-font-family-body);
    font-size: var(--imf-ui-font-size-1);
    font-weight: var(--imf-ui-font-weight-4);
    line-height: var(--imf-ui-font-lineheight-3);
  }

  .TypoLead {
    font-family: var(--imf-ui-font-family-body);
    font-size: var(--imf-ui-font-size-3);
    font-weight: var(--imf-ui-font-weight-4);
    line-height: var(--imf-ui-font-lineheight-3);
  }

  .TypoSmall {
    font-family: var(--imf-ui-font-family-body);
    font-size: var(--imf-ui-font-size-0);
    font-weight: var(--imf-ui-font-weight-4);
    line-height: var(--imf-ui-font-lineheight-2);
  }

  .TypoBlockquote {
    font-family: var(--imf-ui-font-family-body);
    font-size: var(--imf-ui-font-size-2);
    font-weight: var(--imf-ui-font-weight-4);
    line-height: var(--imf-ui-font-lineheight-3);
    font-style: italic;
    padding-inline-start: 1rem;
    border-inline-start: 3px solid var(--imf-ui-color-fg-minor);
  }

  .TypoInlineCode {
    font-family: var(--imf-ui-font-family-code);
    font-size: 0.9em;
    font-weight: var(--imf-ui-font-weight-5);
    line-height: inherit;
    padding: 0.125em 0.375em;
    border-radius: 0.25rem;
    background-color: color-mix(in oklch, var(--imf-ui-color-fg-main) 12%, transparent);
  }

  .TypoHighlight {
    font-family: inherit;
    font-size: inherit;
    font-weight: var(--imf-ui-font-weight-5);
    line-height: inherit;
    padding: 0.05em 0.25em;
    border-radius: 0.2rem;
    background-color: color-mix(in oklch, var(--imf-ui-color-bg-warning) 50%, transparent);
  }

  .TypoOrderedList,
  .TypoUnorderedList {
    font-family: var(--imf-ui-font-family-body);
    font-size: var(--imf-ui-font-size-1);
    font-weight: var(--imf-ui-font-weight-4);
    line-height: var(--imf-ui-font-lineheight-3);
    padding: 0;
    padding-inline-start: 1.5rem;
  }

  .TypoOrderedList {
    list-style: decimal outside;
  }

  .TypoUnorderedList {
    list-style: disc outside;
  }

  .TypoOrderedList > li + li,
  .TypoUnorderedList > li + li {
    margin-top: 0.25rem;
  }

  /* Family-scoped color: every Typo.* element honours data-color via the public attribute */
  [data-imf-ui-component^="Typo."][data-color="main"] {
    color: var(--imf-ui-color-fg-main);
  }
  [data-imf-ui-component^="Typo."][data-color="support"] {
    color: var(--imf-ui-color-fg-support);
  }
  [data-imf-ui-component^="Typo."][data-color="minor"] {
    color: var(--imf-ui-color-fg-minor);
  }
  [data-imf-ui-component^="Typo."][data-color="primary"] {
    color: var(--imf-ui-color-fg-primary);
  }
  [data-imf-ui-component^="Typo."][data-color="negative"] {
    color: var(--imf-ui-color-fg-negative);
  }
  [data-imf-ui-component^="Typo."][data-color="positive"] {
    color: var(--imf-ui-color-fg-positive);
  }
  [data-imf-ui-component^="Typo."][data-color="warning"] {
    color: var(--imf-ui-color-fg-warning);
  }
  [data-imf-ui-component^="Typo."][data-color="info"] {
    color: var(--imf-ui-color-fg-info);
  }
}

